import 'package:flutter/material.dart';
import 'api_client.dart';
import 'auth_service.dart';
import 'login_page.dart';
class HomePage extends StatefulWidget{const HomePage({super.key});@override State<HomePage> createState()=>_HomePageState();}
class _HomePageState extends State<HomePage>{List<dynamic>available=[];List<dynamic>mine=[];String?error;@override void initState(){super.initState();load();}Future<void>load()async{try{final dio=await ApiClient.instance.dio;final a=await dio.get('/courier/jobs/available');final m=await dio.get('/courier/jobs/mine');setState((){available=a.data['data']['data']??[];mine=m.data['data']['data']??[];error=null;});}catch(e){setState(()=>error=e.toString());}}Future<void>claim(dynamic id)async{final dio=await ApiClient.instance.dio;await dio.post('/courier/jobs/$id/claim');await load();}Future<void>logout()async{await AuthService().logout();if(!mounted)return;Navigator.of(context).pushAndRemoveUntil(MaterialPageRoute(builder:(_)=>const LoginPage(title:'IAS Market Courier',role:'courier',deviceName:'IAS Market Courier Android')),(_)=>false);}@override Widget build(BuildContext context)=>Scaffold(appBar:AppBar(title:const Text('IAS Market Courier'),actions:[IconButton(onPressed:logout,icon:const Icon(Icons.logout))]),body:RefreshIndicator(onRefresh:load,child:ListView(padding:const EdgeInsets.all(16),children:[if(error!=null)Text(error!,style:const TextStyle(color:Colors.red)),Text('Tugas tersedia',style:Theme.of(context).textTheme.titleLarge),...available.take(15).map((o)=>Card(child:ListTile(title:Text('${o['order_number']}'),subtitle:Text('${o['store']?['name']??''}\n${o['delivery_address']??''}'),isThreeLine:true,trailing:FilledButton(onPressed:()=>claim(o['id']),child:const Text('Ambil'))))),const SizedBox(height:16),Text('Tugas saya',style:Theme.of(context).textTheme.titleLarge),...mine.take(15).map((o)=>Card(child:ListTile(title:Text('${o['order_number']}'),subtitle:Text('${o['status']}'),trailing:Text('Rp ${o['delivery_fee']}'))))])));}
